args.sparql:
SELECT ?locationLabel ?startDate WHERE {
  ?event wdt:P31 wd:Q198701 ;
         wdt:P585 ?startDate ;
         wdt:P1623 ?location .
  ?location rdfs:label ?locationLabel .
  FILTER (LANG(?locationLabel) = "en") .
  FILTER (?startDate > "2023-01-01"^^xsd:date) .
} ORDER BY ?startDate LIMIT 1

SELECT ?locationLabel ?startDate WHERE {
  ?event wdt:P31 wd:Q198701 ;
         wdt:P1555 wd:Q556745 ;
         wdt:P585 ?startDate ;
         wdt:P276 ?location .
  ?location rdfs:label ?locationLabel .
  FILTER (LANG(?locationLabel) = "en") .
  FILTER (?startDate > "2022-12-31"^^xsd:date) .
  ORDER BY ?startDate
  LIMIT 1
